#include <stdio.h>
#include <stdlib.h>
#include <omp.h>

// Example function with OpenMP parallel for
void example_parallel_function(int *data, int n) {
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; i++) {
        data[i] = i * i;
    }
}

int main(int argc, char **argv) {
    int n = 1024;
    int *data = (int *)malloc(n * sizeof(int));
    if (!data) {
        fprintf(stderr, "Memory allocation failed\n");
        return 1;
    }

    example_parallel_function(data, n);

    // Output the first 10 results
    for (int i = 0; i < 10; i++) {
        printf("data[%d] = %d\n", i, data[i]);
    }

    free(data);
    return 0;
}
